package kotlinx.coroutines.flow

import kotlinx.coroutines.*
import kotlin.test.*

class SharedFlowToCollectionDestinationTest : TestBase() {

    @Test
    fun testSharedFlowToListUsesDestination() = runTest {
        val sh = MutableSharedFlow<Int>(extraBufferCapacity = 16)
        val acc = mutableListOf<Int>()

        val job = launch(start = CoroutineStart.UNDISPATCHED) {
            sh.toList(acc)
        }

        while (sh.subscriptionCount.value == 0) yield()

        sh.emit(1)
        sh.emit(2)
        sh.emit(3)

        while (acc.size < 3) yield()

        job.cancelAndJoin()
        assertEquals(listOf(1, 2, 3), acc)
    }

    @Test
    fun testSharedFlowToSetUsesDestination() = runTest {
        val sh = MutableSharedFlow<Int>(extraBufferCapacity = 16)
        val acc = LinkedHashSet<Int>()

        val job = launch(start = CoroutineStart.UNDISPATCHED) {
            sh.toSet(acc)
        }

        while (sh.subscriptionCount.value == 0) yield()

        sh.emit(1)
        sh.emit(1)
        sh.emit(2)

        while (acc.size < 2) yield()

        job.cancelAndJoin()
        assertEquals(linkedSetOf(1, 2), acc)
    }
}
"}

